INSERT INTO comments (
    post_id, user_id, content, parent_id, like_count, status, created_at, updated_at
) VALUES (
    #{postId}, #{userId}, #{content}, #{parentId}, #{likeCount}, #{status}, NOW(), NOW()
)

mapper.update:
UPDATE comments
SET like_count = like_count + 1
WHERE id = #{id}

UPDATE comments
SET like_count = GREATEST(like_count - 1, 0)
WHERE id = #{id}

mapper.select:
SELECT id, post_id, user_id, content, parent_id, like_count, status, created_at, updated_at
FROM comments
WHERE id = #{id}

SELECT c.id, c.post_id, c.user_id, c.content, c.parent_id, c.like_count, c.status, c.created_at, c.updated_at
FROM comments c


        AND c.content LIKE CONCAT('%', #{keyword}, '%')


        AND c.post_id = #{postId}


        AND c.status = #{status}


ORDER BY c.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM comments c


        AND c.content LIKE CONCAT('%', #{keyword}, '%')


        AND c.post_id = #{postId}


